        <div style="display:flex; justify-content:space-between; align-items:center;"><span><span style="color:${i.sso?'var(--status-green)':'var(--text-muted)'};">●</span> SSO Portal Link</span>${i.sso ? badge('green','Active') : badge('gray','—')}</div>
